package ru.memearena.scout.domain; import jakarta.persistence.*; import java.time.*; import java.util.*; @Entity @Table(name="user_achievement") public class UserAchievement{ @Id private UUID id; @Column(name="user_id") private UUID userId; @Column(name="achievement_code") private String achievementCode; @Column(name="unlocked_at") private Instant unlockedAt; @Column(name="metadata_json") private String metadataJson; protected UserAchievement(){} public UserAchievement(UUID id,UUID userId,String code,Instant now,String meta){this.id=id;this.userId=userId;this.achievementCode=code;this.unlockedAt=now;this.metadataJson=meta;} public String getAchievementCode(){return achievementCode;} public Instant getUnlockedAt(){return unlockedAt;} }
